// Tokens de cor — enumeração de valores semânticos:
extension Color {
    // Tokens semânticos — descrevem propósito, não aparência:
    static let primaryAction = Color("PrimaryAction")  // azul do sistema
    static let destructiveAction = Color("DestructiveAction")  // vermelho
    static let primaryLabel = Color("PrimaryLabel")  // texto principal
    static let secondaryLabel = Color("SecondaryLabel")  // texto secundário
    static let groupedBackground = Color("GroupedBackground")

    // Esses tokens funcionam automaticamente em modo claro e escuro
    // usando Assets.xcassets com variantes de appearance
}

// Tokens de tipografia:
extension Font {
    static let displayLarge = Font.system(.largeTitle, design: .rounded, weight: .bold)
    static let headingMedium = Font.headline
    static let bodyRegular = Font.body
    static let captionSmall = Font.caption
}

// Tokens de espaçamento:
struct Spacing {
    static let xxs: CGFloat = 4
    static let xs: CGFloat = 8
    static let sm: CGFloat = 12
    static let md: CGFloat = 16
    static let lg: CGFloat = 24
    static let xl: CGFloat = 32
    static let xxl: CGFloat = 48
}

// Componente PrimaryButton — encapsula design e comportamento:
struct PrimaryButton: View {
    let titulo: String
    var isLoading: Bool = false
    var isDestructive: Bool = false
    let acao: () -> Void

    private var corFundo: Color {
        isDestructive ? .destructiveAction : .primaryAction
    }

    var body: some View {
        Button(acao) {
            Group {
                if isLoading {
                    ProgressView().tint(.white)
                } else {
                    Text(titulo)
                        .font(.bodyRegular)
                        .fontWeight(.semibold)
                }
            }
            .frame(maxWidth: .infinity)
        }
        .padding(.vertical, Spacing.md)
        .padding(.horizontal, Spacing.lg)
        .background(corFundo)
        .foregroundStyle(.white)
        .clipShape(RoundedRectangle(cornerRadius: 12))
        .disabled(isLoading)
    }
}

// Uso consistente em qualquer tela:
PrimaryButton(titulo: "Salvar") { salvar() }
PrimaryButton(titulo: "Deletar conta", isDestructive: true) { deletar() }
PrimaryButton(titulo: "Enviando...", isLoading: true) { }

// SF Symbols com configuração consistente:
Image(systemName: "star.fill")
    .symbolRenderingMode(.hierarchical)  // modo de renderização
    .foregroundStyle(.primaryAction)
    .font(.title2)

// Variantes com environment:
Image(systemName: "person")
    .symbolVariant(.circle.fill)  // person.circle.fill

// Animação nativa (iOS 17+):
Image(systemName: botaoPressionado ? "heart.fill" : "heart")
    .contentTransition(.symbolEffect(.replace))
    .foregroundStyle(botaoPressionado ? Color.red : .secondary)
    .onTapGesture { botaoPressionado.toggle() }

// Icone com badge (iOS 17+):
Image(systemName: "bell")
    .overlay(alignment: .topTrailing) {
        Image(systemName: "circle.fill")
            .font(.system(size: 8))
            .foregroundStyle(.red)
            .symbolVariant(.fill)
    }

// REGRA HIG: Alvo mínimo de toque = 44x44 pontos
// Ícones pequenos precisam de área de toque maior que o visual:
Button {
    acao()
} label: {
    Image(systemName: "ellipsis")
        .font(.body)
        .frame(width: 44, height: 44)  // área de toque mínima
}

// REGRA HIG: Usar materiais do sistema para backgrounds de barra:
.toolbarBackground(.visible, for: .navigationBar)
.toolbarBackground(Material.bar, for: .navigationBar)

// REGRA HIG: NavigationBar para hierarquia linear;
// TabBar para navegação entre seções irmãs
// (não use TabBar dentro de NavigationStack)
tabBarItem: {
    Label("Início", systemImage: "house")
}

// REGRA HIG: Destructive actions em vermelho, com confirmação:
Button("Deletar conta", role: .destructive) {
    mostrarConfirmacao = true
}
.confirmationDialog("Tem certeza?", isPresented: $mostrarConfirmacao) {
    Button("Deletar permanentemente", role: .destructive) { deletar() }
    Button("Cancelar", role: .cancel) { }
}
